// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) {
    return;
  }

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);
  // inObj가 코드 필드일 경우 팝업
  if (isCode == null || isCode == true) {
    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
  } else {
    // inObj가 코드명 필드일 경우 팝업
    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
  }
};

// 금액계산
scwin.f_SumAmt = function () {
  var spplyAmtFcrc = 0;
  var spplyAmt = 0;
  var totAmt = 0;
  for (var i = 0; i < ds_BillList.getRowCount(); i++) {
    if (ds_BillList.getCellData(i, "choice") == "T") {
      spplyAmtFcrc = spplyAmtFcrc + Number(ds_BillList.getCellData(i, "spplyAmtFcrc"));
      spplyAmt = spplyAmt + Number(ds_BillList.getCellData(i, "spplyAmt"));
      totAmt = totAmt + Number(ds_BillList.getCellData(i, "totAmt"));
    }
    ds_BillList.setCellData(i, "vatAmt", Number(ds_BillList.getCellData(i, "totAmt")) - Number(ds_BillList.getCellData(i, "spplyAmt")));
  }
  ed_spplyAmtFcrc.setValue($c.gus.cfInsertComma($p, spplyAmtFcrc));
  ed_spplyAmt.setValue($c.gus.cfInsertComma($p, spplyAmt));
  ed_totAmt.setValue($c.gus.cfInsertComma($p, totAmt));
  ed_vatAmt.setValue($c.gus.cfInsertComma($p, totAmt - spplyAmt));
};

