// 인쇄 (BILL)
scwin.f_billPrint = async function () {
  let printCnt = 0,
    oz,
    odi,
    ozr;
  for (var i = 0; i < ds_BillList.getRowCount(); i++) {
    if (ds_BillList.getCellData(i, "choice") == "T") {
      printCnt++;
    }
  }
  if (printCnt == 0) {
    let msg = $c.data.getMessage($p, MSG_CM_WRN_007, "발행할 BILL");
    return await $c.win.alert($p, msg);
  }
  if (cbx_checkbox1.getValue() == "Y") {
    for (let i = 0; i < ds_BillList.getRowCount(); i++) {
      if (ds_BillList.getCellData(i, "choice") == "T") {
        oz = ds_BillList.getCellData(i, "inscrpFmlaPatternCd");
        odi = oz;
        // 기본 공통양식(04)
        if (oz == "04") {
          ozr = odi + "_" + ds_BillList.getCellData(i, "billCoverFmlaClsCd");
          // 개별양식(31,32)
        } else {
          ozr = oz;
        }
        const data = {
          reportName: "/ds/fs/fs_202_05_21_" + ozr + ".ozr",
          odiName: "fs_202_05_21_" + odi,
          odiParam: {
            bilgLodeptCd: ds_BillList.getCellData(i, "bilgLodeptCd"),
            certiNo: ds_BillList.getCellData(i, "certiNo"),
            type: ds_BillList.getCellData(i, "billCoverFmlaClsCd")
          },
          viewerParam: {
            mode: "silent",
            zoom: 100,
            copies: Number(ed_printPage.getValue()),
            useprogressbar: false
          },
          formParam: {}
        };
        await scwin.openPopup(data);
      }
    }
  } else {
    const exportData = [];
    for (let i = 0; i < ds_BillList.getRowCount(); i++) {
      if (ds_BillList.getCellData(i, "choice") == "T") {
        oz = ds_BillList.getCellData(i, "inscrpFmlaPatternCd");
        odi = oz;
        // 기본 공통양식(04)
        if (oz == "04") {
          ozr = odi + "_" + ds_BillList.getCellData(i, "billCoverFmlaClsCd");
          // 개별양식(31,32)
        } else {
          ozr = oz;
        }
        exportData.push({
          reportName: "/ds/fs/fs_202_05_21_" + ozr + ".ozr",
          odiName: "fs_202_05_21_" + odi,
          odiParam: {
            bilgLodeptCd: ds_BillList.getCellData(i, "bilgLodeptCd"),
            certiNo: ds_BillList.getCellData(i, "certiNo"),
            type: ds_BillList.getCellData(i, "billCoverFmlaClsCd")
          }
        });
      }
    }
    scwin.openBatchOzReport(exportData);
  }
};

