scwin.gr_BillList_oncellclick = function (rowIndex, columnIndex, columnId) {
  if (columnId == "certiNo") {
    if (ds_BillList.getCellData(rowIndex, "choice") == "T") {
      ed_mainCertiNo.setValue(ds_BillList.getCellData(rowIndex, "certiNo"));
      ed_vssl.setValue(ds_BillList.getCellData(rowIndex, "inscrpVsslCd"));
      ed_vsslNm.setValue(ds_BillList.getCellData(rowIndex, "vsslNm"));
      ica_arDepPortDt.setValue(ds_BillList.getCellData(rowIndex, "arDepPortDt"));
    }
  }
  if (columnId == "choice") {
    if (ds_BillList.getCellData(rowIndex, "choice") == "F" && ds_BillList.getCellData(rowIndex, "certiNo") == ed_mainCertiNo.value) {
      ed_mainCertiNo.setValue("");
      ed_vssl.setValue("");
      ed_vsslNm.setValue("");
      ica_arDepPortDt.setValue("");
    }
    scwin.f_SumAmt();
  }
};

